import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.ExclusionStrategy;
import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentMatchers;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Type;

class ExcluderTest {

  private Excluder excluder;

  @BeforeEach
  void setUp() {
    excluder = new Excluder();
  }

  @Test
  void create_shouldReturnNullIfNotExcluded() {
    Gson gson = mock(Gson.class);
    TypeToken<String> typeToken = TypeToken.get(String.class);

    TypeAdapter<String> adapter = excluder.create(gson, typeToken);

    assertNull(adapter);
  }

  @Test
  void create_shouldReturnTypeAdapterThatSkipsDeserialize() throws IOException {
    Gson gson = mock(Gson.class);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    Excluder spyExcluder = Mockito.spy(excluder);
    // Force excludeClass to true to skip serialization and deserialization
    doReturn(true).when(spyExcluder).excludeClassChecks(Object.class);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(any(), anyBoolean());

    TypeAdapter<Object> adapter = spyExcluder.create(gson, typeToken);

    assertNotNull(adapter);

    JsonReader jsonReader = mock(JsonReader.class);
    Object result = adapter.read(jsonReader);

    verify(jsonReader).skipValue();
    assertNull(result);
  }

  @Test
  void create_shouldReturnTypeAdapterThatSkipsSerialize() throws IOException {
    Gson gson = mock(Gson.class);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    Excluder spyExcluder = Mockito.spy(excluder);
    // Force excludeClassInStrategy to true for serialization only
    doReturn(false).when(spyExcluder).excludeClassChecks(Object.class);
    doReturn(true).when(spyExcluder).excludeClassInStrategy(Object.class, true);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(Object.class, false);

    TypeAdapter<Object> adapter = spyExcluder.create(gson, typeToken);

    assertNotNull(adapter);

    JsonWriter jsonWriter = mock(JsonWriter.class);
    Object value = new Object();
    adapter.write(jsonWriter, value);

    verify(jsonWriter).nullValue();
  }

  @Test
  void create_shouldDelegateReadAndWriteWhenNotSkipped() throws IOException {
    Gson gson = mock(Gson.class);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    Excluder spyExcluder = Mockito.spy(excluder);
    doReturn(false).when(spyExcluder).excludeClassChecks(Object.class);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(Object.class, true);
    doReturn(false).when(spyExcluder).excludeClassInStrategy(Object.class, false);

    TypeAdapter<Object> delegateAdapter = mock(TypeAdapter.class);
    when(gson.getDelegateAdapter(spyExcluder, typeToken)).thenReturn(delegateAdapter);

    TypeAdapter<Object> adapter = spyExcluder.create(gson, typeToken);

    assertNull(adapter);

    // Now test with exclusion to get non-null adapter and delegate calls
    doReturn(true).when(spyExcluder).excludeClassChecks(Object.class);

    adapter = spyExcluder.create(gson, typeToken);
    assertNotNull(adapter);

    JsonReader jsonReader = mock(JsonReader.class);
    Object expectedRead = new Object();
    when(delegateAdapter.read(jsonReader)).thenReturn(expectedRead);
    Object actualRead = adapter.read(jsonReader);
    assertSame(expectedRead, actualRead);

    JsonWriter jsonWriter = mock(JsonWriter.class);
    Object value = new Object();
    adapter.write(jsonWriter, value);
    verify(delegateAdapter).write(jsonWriter, value);
  }
}
